struct Shape {
  virtual double area() const = 0;
  virtual ~Shape() = default;
};
struct Circle : Shape {
  double r;
  explicit Circle(double r) : r(r) {}
  double area() const override { return 3.14159 * r * r; }
};

std::unique_ptr<Shape> s = std::make_unique<Circle>(2.0);
std::cout << s->area(); // dispatches to Circle::area

// Rule of Zero: members manage their own resources
class Buffer {
  std::vector<char> data_;
public:
  explicit Buffer(std::size_t n) : data_(n) {}
  // no destructor, copy, or move needed
};

class Str {
  char* p_; std::size_t n_;
public:
  Str(const Str& o) : n_(o.n_), p_(new char[o.n_]) {   // copy
    std::copy(o.p_, o.p_ + n_, p_);
  }
  Str(Str&& o) noexcept : p_(o.p_), n_(o.n_) {          // move
    o.p_ = nullptr; o.n_ = 0;
  }
  ~Str() { delete[] p_; }
};

struct Vec2 {
  double x, y;
